documentModels.schema:
type ToDoDocumentState {
  items: [ToDoItem!]!
  stats: ToDoListStats!
}

type ToDoItem {
  id: ID!
  text: String!
  checked: Boolean!
}

type ToDoListStats {
  total: Int!
  checked: Int!
  unchecked: Int!
}

type FinancialReport {
  revenue: Float!
  expenses: [Expense!]!
  profit: Float!
}

type TechSpec {
  title: String!
  requirements: [Requirement!]!
  architecture: Architecture!
}
